      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}

export function emitIntegrationSeo(
  data: IntegrationPageData,
  url: IntegrationUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = `${url}/opengraph-image`;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast Integrations`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast Integrations",
        locale: "en_US",
        images: [
          { url: ogImageUrl, width: 1200, height: 630, alt: data.ogTitle },
        ],
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [ogImageUrl],
      },
    }),
    jsonLd: buildIntegrationJsonLd(data, url),
  };
}

export function emitApiRefSeo(
  data: DocsPageData,
  url: ApiRefUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = url.replace(
    "/docs/api-reference/",
    "/docs/api-reference/og/"
  );
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast API Reference",
      "Lightfast API Reference",
      ogImageUrl
    ),
    jsonLd: buildApiRefJsonLd(data, url, breadcrumbs),
  };
}

import type { Thing, WithContext } from "schema-dts";

// Type for JSON-LD Graph structure.
// @context is intentionally `string` (not the literal "https://schema.org") to
// stay spec-compliant — JSON-LD allows any URI, inline objects, or arrays.
// Use WithContext<Thing> when a strict "https://schema.org" literal is needed.
interface GraphContext {
  "@context":
    | string
    | Record<string, unknown>
    | (string | Record<string, unknown>)[];
  "@graph": Thing[];
}

// Union type supporting both single entities and graph structures
type JsonLdData = WithContext<Thing> | GraphContext;

interface JsonLdProps {
  code: JsonLdData;
}

const escapeJsonForHtml = (json: string): string =>
  json
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");

export const JsonLd = ({ code }: JsonLdProps) => (
  <script
    // biome-ignore lint/security/noDangerouslySetInnerHtml: JSON-LD must be injected via script tag; content is escaped
    dangerouslySetInnerHTML={{
      __html: escapeJsonForHtml(JSON.stringify(code)),
    }}
    type="application/ld+json"
  />
);

// Export types for use in components
export type { GraphContext, JsonLdData };

// Re-export commonly used schema types for convenience
export type {
  Answer,
  // Content types
  Article,
  Blog,
  BlogPosting,
  BreadcrumbList,
  // Event types
  Event,
  FAQPage,
  HowTo,
  HowToStep,
  // Media types
  ImageObject,
  ListItem,
  Offer,
  // Organization types
  Organization,
  // Person types
  Person,
  Product,
  Question,
  Service,
  // Product/Service types
  SoftwareApplication,
  TechArticle,
  // Core types
  Thing,
  VideoObject,
  WebPage,
  // Website types
  WebSite,
  WithContext,
} from "schema-dts";
